const helpers = this.helpers;
const SUPABASE_URL = $env.SUPABASE_URL;
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;

const body = $input.first().json?.body || {};
const { telefono_wa } = body;

if (!telefono_wa) return [{ json: { ok: false, error: 'telefono_wa requerido' } }];

const fmt = p => { let s=p.replace(/[^0-9]/g,''); if(s.startsWith('54')&&s.length>=12) return s; if(s.length===10) return '549'+s; return s; };
const phone = fmt(telefono_wa);

await helpers.httpRequest({
  method: 'PATCH',
  url: `${SUPABASE_URL}/rest/v1/consultorio_conversaciones`,
  qs: { telefono_wa: `eq.${phone}` },
  headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json' },
  body: JSON.stringify({ estado: 'inicio', contexto: {}, handoff_humano: false, updated_at: new Date().toISOString() })
});

return [{ json: { ok: true, phone } }];

